import{_ as a,o as e,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const p=JSON.parse('{"title":"排云殿","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/summer-palace/paiyun-dian.md","filePath":"landmarks/summer-palace/paiyun-dian.md","lastUpdated":1784720050000}'),n={name:"landmarks/summer-palace/paiyun-dian.md"};function i(o,t,s,d,g,h){return e(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="排云殿" tabindex="-1">排云殿 <a class="header-anchor" href="#排云殿" aria-label="Permalink to &quot;排云殿&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1704852285252-cf86631cbe22?w=1200&amp;q=80" alt="排云殿"></p><blockquote><p>&quot;神仙排云出，但见金银台。&quot; —— 郭璞《游仙诗》中的仙境，慈禧万寿节的舞台</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>排云殿位于万寿山前山中央，背倚<a href="/beijing-travel-guide/landmarks/summer-palace/foxiang-ge.html">佛香阁</a>，面朝昆明湖，是颐和园中轴线上的核心殿宇，也是慈禧太后举行万寿庆典、接受朝贺的场所。</p><p>殿名取自晋代郭璞《游仙诗》&quot;神仙排云出，但见金银台&quot;之句，寓意此处如仙山琼阁，云雾缭绕间神仙排云而出——既写山势之高，也暗合慈禧自比&quot;老佛爷&quot;的心思。</p><p>这里的前身是大报恩延寿寺，始建于乾隆十五年（1750年），为乾隆庆祝母亲六十大寿所建。1860年寺院毁于英法联军之手，光绪年间慈禧重建时，将寺院改为殿堂，命名&quot;排云殿&quot;。此后每年十月初十慈禧寿辰，光绪帝率王公百官在此行三跪九叩大礼，是晚清宫廷最隆重的典礼现场。</p><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">年代</th><th style="text-align:left;">大事</th></tr></thead><tbody><tr><td style="text-align:left;">清乾隆十五年（1750）</td><td style="text-align:left;">建大报恩延寿寺，为崇庆皇太后祝寿之所</td></tr><tr><td style="text-align:left;">咸丰十年（1860）</td><td style="text-align:left;">随清漪园遭英法联军焚毁</td></tr><tr><td style="text-align:left;">清光绪年间</td><td style="text-align:left;">寺改殿，重建为排云殿，成为万寿庆典场所</td></tr><tr><td style="text-align:left;">光绪三十年（1904）</td><td style="text-align:left;">慈禧七旬万寿，排云殿举行盛大庆典</td></tr><tr><td style="text-align:left;">1924年</td><td style="text-align:left;">随颐和园对外开放</td></tr></tbody></table><h2 id="建筑与景观" tabindex="-1">建筑与景观 <a class="header-anchor" href="#建筑与景观" aria-label="Permalink to &quot;建筑与景观&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>前身</strong></td><td style="text-align:left;">大报恩延寿寺（清乾隆十五年，1750年建）</td></tr><tr><td style="text-align:left;"><strong>殿宇规制</strong></td><td style="text-align:left;">面阔五间，重檐歇山顶，黄琉璃瓦，前后出廊</td></tr><tr><td style="text-align:left;"><strong>中轴序列</strong></td><td style="text-align:left;">排云门 → 芳辉殿 → 排云殿 → 德辉殿 → 佛香阁 → 智慧海</td></tr><tr><td style="text-align:left;"><strong>殿前陈设</strong></td><td style="text-align:left;">铜狮、铜缸、铜鹿、铜鹤、铜鼎，月台设铜鼎香炉</td></tr><tr><td style="text-align:left;"><strong>殿内陈设</strong></td><td style="text-align:left;">慈禧御座、宝座屏风、掌扇宫灯、&quot;复殿留云&quot;匾</td></tr><tr><td style="text-align:left;"><strong>功能</strong></td><td style="text-align:left;">慈禧万寿节受贺、朝会大典之所</td></tr></tbody></table><p>排云殿建筑群沿山势层层递升，以排云门为起点，经芳辉殿、紫霄殿夹峙两翼，主殿排云殿踞于高台之上，其后德辉殿紧接登山磴道直通佛香阁。</p><p>殿前月台宽阔，可陈设仪仗卤簿，容纳百官朝贺。殿内陈设为光绪朝原状：正中设慈禧御座，宝座后立屏风，两侧掌扇、宫灯俱全，一派皇家威仪。</p><h2 id="历史故事" tabindex="-1">历史故事 <a class="header-anchor" href="#历史故事" aria-label="Permalink to &quot;历史故事&quot;">​</a></h2><h3 id="十月初十的万寿盛典" tabindex="-1">十月初十的万寿盛典 <a class="header-anchor" href="#十月初十的万寿盛典" aria-label="Permalink to &quot;十月初十的万寿盛典&quot;">​</a></h3><p>慈禧生于道光十五年十月初十（1835年11月29日），此后每逢此日便是清宫最盛大的节日。颐和园重建后，万寿节庆典移师排云殿：天未亮，光绪帝已率群臣在排云门外候驾，吉时一到，慈禧升座，百官山呼&quot;万寿无疆&quot;，三跪九叩，乐舞齐奏。</p><p>据档案记载，庆典前数日，从东宫门到排云殿一路扎彩棚、悬宫灯，昆明湖上龙舟竞渡，极尽铺张。彼时国库空虚、外患频仍，排云殿前的每一次叩拜，都是晚清&quot;量中华之物力，结与国之欢心&quot;的注脚。</p><h3 id="六十大寿的遗憾" tabindex="-1">六十大寿的遗憾 <a class="header-anchor" href="#六十大寿的遗憾" aria-label="Permalink to &quot;六十大寿的遗憾&quot;">​</a></h3><p>1894年（甲午年）本是慈禧六十大寿，朝廷早早在排云殿筹备庆典，挪用海军军费修缮园林、置办戏装。然而这一年甲午战争爆发，北洋水师节节败退，群臣弹劾，慈禧被迫下旨&quot;庆典从简&quot;，万寿节改在紫禁城内草草举行。</p><p>排云殿前张好的彩棚黯然撤去，两年后《马关条约》签订，割地赔款。一座殿宇的庆典兴衰，恰是一个帝国的黄昏缩影。</p><h3 id="从佛寺到朝堂" tabindex="-1">从佛寺到朝堂 <a class="header-anchor" href="#从佛寺到朝堂" aria-label="Permalink to &quot;从佛寺到朝堂&quot;">​</a></h3><p>排云殿的前身大报恩延寿寺，本是乾隆为母亲祈福的佛门净地，香火鼎盛近百年。慈禧将其改为朝贺殿堂，佛堂变朝堂，颂经声换成山呼声——建筑的功能转换，折射出这座园林从&quot;帝王孝亲&quot;到&quot;太后专权&quot;的气质之变。有趣的是，寺内部分佛像并未移走，至今山巅智慧海仍供着琉璃佛像，佛与权在同一座山上共处了一百多年。</p><h2 id="必看亮点" tabindex="-1">必看亮点 <a class="header-anchor" href="#必看亮点" aria-label="Permalink to &quot;必看亮点&quot;">​</a></h2><ol><li><strong>中轴线气象</strong>：排云门至佛香阁的层层台地，是颐和园最见皇家气派的轴线，殿前回望昆明湖，湖山一览无余。</li><li><strong>万寿庆典陈列</strong>：殿内复原慈禧受贺场景，御座、屏风、贡品清单一目了然，比空殿更有故事。</li><li><strong>殿前铜兽</strong>：铜狮、铜缸、铜鹤、铜鹿列置月台，多为乾隆朝清漪园旧物，躲过1860年大火，弥足珍贵。</li><li><strong>芳辉殿与紫霄殿</strong>：两翼配殿现为宫廷生活展室，展示慈禧起居用品，细节处见奢华。</li><li><strong>登山起点</strong>：从排云殿后的德辉殿拾级而上，二十分钟即可登顶<a href="/beijing-travel-guide/landmarks/summer-palace/foxiang-ge.html">佛香阁</a>，是体力游的最佳路线。</li></ol><h2 id="拍照机位" tabindex="-1">拍照机位 <a class="header-anchor" href="#拍照机位" aria-label="Permalink to &quot;拍照机位&quot;">​</a></h2><ol><li><strong>月台回望</strong>：站在排云殿月台南缘俯拍，昆明湖与十七孔桥尽收镜头，前景是铜兽与汉白玉栏杆。</li><li><strong>中轴仰拍</strong>：从排云门内仰拍，殿宇、飞檐、佛香阁层层叠起，气势十足。</li><li><strong>铜兽特写</strong>：清晨侧光下，月台铜鹤铜鹿的金属质感最动人。</li></ol><h2 id="参观贴士" tabindex="-1">参观贴士 <a class="header-anchor" href="#参观贴士" aria-label="Permalink to &quot;参观贴士&quot;">​</a></h2><ol><li>排云殿需持联票或另购票参观，属园中园范围，与佛香阁同票通用。</li><li>殿内禁止拍照，但殿前月台和铜兽区可以尽情拍，清晨侧光时铜器质感最佳。</li><li>中轴线台阶陡峭，老人小孩建议缓行；不想爬山者可只参观殿内陈列，登山段量力而行。</li><li>排云殿与<a href="/beijing-travel-guide/landmarks/summer-palace/changlang.html">长廊</a>仅一墙之隔，从长廊中部的排云门进入最为顺路。</li><li>逛完排云殿沿中轴登顶佛香阁，再下山至<a href="/beijing-travel-guide/landmarks/summer-palace/shifang.html">石舫</a>，是<a href="/beijing-travel-guide/landmarks/summer-palace/">北宫门线</a>最经典的山水连游。</li><li>想感受&quot;万寿节&quot;氛围，可留意每年十月初十前后的园方纪念活动。</li></ol><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><p><strong>Q：排云殿和佛香阁是什么关系？</strong></p><p>二者在同一条中轴线上：排云殿是山脚的朝贺正殿，<a href="/beijing-travel-guide/landmarks/summer-palace/foxiang-ge.html">佛香阁</a>是山巅的宗教地标，一殿一阁，一俗一圣，拾级可连游。</p><p><strong>Q：排云殿现在做什么用？</strong></p><p>殿内辟有慈禧万寿庆典陈列，复原了御座、屏风与受贺场景，比空殿更有看头。</p><p><strong>Q：万寿节是哪一天？</strong></p><p>农历十月初十，慈禧的生日。这一天是晚清宫廷最隆重的节日，王公百官要在排云殿行三跪九叩大礼。</p><p><strong>Q：从排云殿爬到佛香阁要多久？</strong></p><p>经德辉殿登山磴道，约20-30分钟；台阶陡峭，量力缓行，回望湖景则越爬越值。</p><hr><p><strong>📍 位置</strong>：万寿山前山中央，长廊北侧、佛香阁下 <strong>⏱️ 建议游览</strong>：30-40分钟 <strong>🔗 返回</strong>：<a href="/beijing-travel-guide/landmarks/summer-palace/">颐和园概览</a></p>',39)])])}const m=a(n,[["render",i]]);export{p as __pageData,m as default};
